### 파일 1: `src/features/app/domain/DomainListPage.jsx`

기존 domain/DomainListPage.jsx 패턴 재사용, Dialog 대신 navigate('/app/domains/:id'):

```jsx
import { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { CardList } from '@/shared/components/CardList/CardList';
import { SearchForm } from '@/shared/components/SearchForm/SearchForm';
import { Input } from '@/shared/components/ui/input';
import { Label } from '@/shared/components/ui/label';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/shared/components/ui/select';
import { Badge } from '@/shared/components/ui/badge';
import { Card } from '@/shared/components/ui/card';
import { emptyToNull } from '@/shared/query/queryHelpers';
import { useListPage } from '@/shared/hooks/useListPage';

const dataTypeOptions = Object.freeze(['VARCHAR', 'CHAR', 'NUMERIC', 'DATETIME']);

const initialFilters = Object.freeze({
    stdDmnNm: '', stdDmnGroupNm: '', stdDmnClsfNm: '', dataTypeNm: '', useYn: '',
});

const DomainCard = ({ domain, onClick }) => (
    <Card
        className='cursor-pointer border-[1.5px] border-border-lt p-4 hover:border-accent transition-colors bg-bg rounded-sm'
        onClick={() => onClick(domain)}
    >
        <div className='flex items-start justify-between gap-3'>
            <div className='min-w-0 flex-1'>
                <div className='mb-1 flex items-baseline gap-2 flex-wrap'>
                    <span className='font-display italic font-bold text-[18px] text-fg'>{domain.stdDmnNm}</span>
                    {domain.dataLen && (
                        <span className='font-mono text-[12px] text-muted-foreground'>
                            {domain.dataTypeNm}({domain.dataLen}{domain.unitNm ? ` ${domain.unitNm}` : ''})
                        </span>
                    )}
                </div>
                <div className='text-[12px] text-muted-foreground flex items-center gap-4 flex-wrap'>
                    {domain.stdDmnGroupNm && <span>{domain.stdDmnGroupNm}</span>}
                    {domain.stdDmnClsfNm && <span>{domain.stdDmnClsfNm}</span>}
                    {domain.enctCycl && <span>제정 {domain.enctCycl}차</span>}
                </div>
            </div>
            <div className='flex items-center gap-1.5 shrink-0'>
                {domain.dataTypeNm && !domain.dataLen && <Badge variant='info'>{domain.dataTypeNm}</Badge>}
                <Badge variant={domain.useYn === 'Y' ? 'success' : 'muted'}>
                    {domain.useYn === 'Y' ? '사용' : '미사용'}
                </Badge>
            </div>
        </div>
    </Card>
);

export const DomainListPage = () => {
    const [filters, setFilters] = useState(initialFilters);
    const navigate = useNavigate();
    const { request, setRequest, pageQuery } = useListPage({
        listQueryKey: 'domain-list',
        listUrl: '/domains/search',
        detailQueryKey: 'domain-detail',
        detailUrl: '/domains',
        initialRequest: { page: 1, size: 20 },
    });

    return (
        <div className='space-y-4'>
            <header className='pb-5 border-b border-border-lt mb-5'>
                <h1 className='font-display italic font-bold text-[26px] m-0 mb-1' style={{ letterSpacing: '-0.02em' }}>
                    도메인
                </h1>
                <p className='text-[13px] text-muted-foreground m-0'>행정표준용어 기반 도메인 분류 데이터</p>
            </header>

            <SearchForm
                onSubmit={() => setRequest({
                    page: 1, size: request.size,
                    stdDmnNm: emptyToNull(filters.stdDmnNm),
                    stdDmnGroupNm: emptyToNull(filters.stdDmnGroupNm),
                    stdDmnClsfNm: emptyToNull(filters.stdDmnClsfNm),
                    dataTypeNm: emptyToNull(filters.dataTypeNm),
                    useYn: emptyToNull(filters.useYn),
                })}
                onReset={() => { setFilters(initialFilters); setRequest({ page: 1, size: request.size }); }}
            >
                <div className='grid w-full gap-3 md:grid-cols-2 xl:grid-cols-5'>
                    <div className='space-y-2'>
                        <Label htmlFor='stdDmnNm'>도메인명</Label>
                        <Input id='stdDmnNm' value={filters.stdDmnNm}
                            onChange={(e) => setFilters((c) => ({ ...c, stdDmnNm: e.target.value }))} />
                    </div>
                    <div className='space-y-2'>
                        <Label htmlFor='stdDmnGroupNm'>그룹명</Label>
                        <Input id='stdDmnGroupNm' value={filters.stdDmnGroupNm}
                            onChange={(e) => setFilters((c) => ({ ...c, stdDmnGroupNm: e.target.value }))} />
                    </div>
                    <div className='space-y-2'>
                        <Label htmlFor='stdDmnClsfNm'>분류명</Label>
                        <Input id='stdDmnClsfNm' value={filters.stdDmnClsfNm}
                            onChange={(e) => setFilters((c) => ({ ...c, stdDmnClsfNm: e.target.value }))} />
                    </div>
                    <div className='space-y-2'>
                        <Label htmlFor='dataTypeNm'>데이터타입</Label>
                        <Select value={filters.dataTypeNm || 'ALL'}
                            onValueChange={(v) => setFilters((c) => ({ ...c, dataTypeNm: v === 'ALL' ? '' : v }))}>
                            <SelectTrigger id='dataTypeNm' className='bg-background'><SelectValue placeholder='전체' /></SelectTrigger>
                            <SelectContent>
                                <SelectItem value='ALL'>전체</SelectItem>
                                {dataTypeOptions.map((opt) => <SelectItem key={opt} value={opt}>{opt}</SelectItem>)}
                            </SelectContent>
                        </Select>
                    </div>
                    <div className='space-y-2'>
                        <Label htmlFor='useYn'>사용여부</Label>
                        <Select value={filters.useYn || 'ALL'}
                            onValueChange={(v) => setFilters((c) => ({ ...c, useYn: v === 'ALL' ? '' : v }))}>
                            <SelectTrigger id='useYn' className='bg-background'><SelectValue placeholder='전체' /></SelectTrigger>
                            <SelectContent>
                                <SelectItem value='ALL'>전체</SelectItem>
                                <SelectItem value='Y'>사용</SelectItem>
                                <SelectItem value='N'>미사용</SelectItem>
                            </SelectContent>
                        </Select>
                    </div>
                </div>
            </SearchForm>

            <CardList
                pageData={pageQuery.data ?? null}
                pageSizeOptions={[10, 20, 50, 100]}
                onPageChange={({ page, size }) => setRequest((c) => ({ ...c, page, size }))}
                renderItem={(domain) => (
                    <DomainCard key={domain.id} domain={domain} onClick={(d) => navigate(`/app/domains/${d.id}`)} />
                )}
            />
        </div>
    );
};
