### 파일 3: `src/features/app/forbidden/ForbiddenPage.jsx`

실시간 스캐너 + 목록:

```jsx
import { useState, useMemo } from 'react';
import { useQuery } from '@tanstack/react-query';
import { CardList } from '@/shared/components/CardList/CardList';
import { SearchForm } from '@/shared/components/SearchForm/SearchForm';
import { Input } from '@/shared/components/ui/input';
import { Label } from '@/shared/components/ui/label';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/shared/components/ui/select';
import { Badge } from '@/shared/components/ui/badge';
import { Card } from '@/shared/components/ui/card';
import { emptyToNull } from '@/shared/query/queryHelpers';
import { useListPage } from '@/shared/hooks/useListPage';
import { axiosInstance } from '@/shared/api/axiosInstance';  // 경로 확인

const fetchAllForbidden = () =>
    axiosInstance.get('/api/v1/forbiddens/search?size=9999').then((r) => r.data?.data?.items ?? []);

const initialFilters = Object.freeze({ phwrdNm: '', useYn: '' });

const ForbiddenCard = ({ forbidden }) => (
    <Card className='border-[1.5px] border-border-lt p-4 bg-bg rounded-sm'>
        <div className='flex items-start justify-between gap-3'>
            <div className='min-w-0 flex-1'>
                <span className='font-display italic font-bold text-[18px] text-fg'>{forbidden.phwrdNm}</span>
                <div className='text-[12px] text-muted-foreground flex items-center gap-4 flex-wrap mt-1'>
                    {forbidden.enctCycl && <span>제정 {forbidden.enctCycl}차</span>}
                    {forbidden.rmrkCn && <span className='truncate max-w-[400px]'>{forbidden.rmrkCn}</span>}
                </div>
            </div>
            <Badge variant={forbidden.useYn === 'Y' ? 'success' : 'muted'}>
                {forbidden.useYn === 'Y' ? '사용' : '미사용'}
            </Badge>
        </div>
    </Card>
);

export const ForbiddenPage = () => {
    const [scanText, setScanText] = useState('');
    const [filters, setFilters] = useState(initialFilters);

    const { data: allForbidden = [] } = useQuery({
        queryKey: ['forbidden-all'],
        queryFn: fetchAllForbidden,
        staleTime: 5 * 60 * 1000,
    });

    const violations = useMemo(
        () => allForbidden.filter((f) => f.useYn === 'Y' && scanText.includes(f.phwrdNm)),
        [scanText, allForbidden],
    );

    const { request, setRequest, pageQuery } = useListPage({
        listQueryKey: 'forbidden-list',
        listUrl: '/forbiddens/search',
        detailQueryKey: 'forbidden-detail',
        detailUrl: '/forbiddens',
        initialRequest: { page: 1, size: 20 },
    });

    return (
        <div className='space-y-8'>
            <header className='pb-5 border-b border-border-lt'>
                <h1 className='font-display italic font-bold text-[26px] m-0 mb-1' style={{ letterSpacing: '-0.02em' }}>
                    금칙어
                </h1>
                <p className='text-[13px] text-muted-foreground m-0'>사용 금지 단어 관리 및 실시간 검사</p>
            </header>

            {/* 실시간 스캐너 */}
            <section>
                <p className='text-[11px] font-bold tracking-[0.1em] uppercase text-muted-foreground mb-3'>실시간 스캐너</p>
                <div className='grid grid-cols-1 xl:grid-cols-[1fr_280px] gap-4'>
                    <div>
                        <textarea
                            className='w-full h-32 p-3 text-[13px] border border-border-lt bg-surface rounded-sm resize-none focus:outline-none focus:border-accent font-mono'
                            placeholder='검사할 텍스트를 입력하세요...'
                            value={scanText}
                            onChange={(e) => setScanText(e.target.value)}
                        />
                    </div>
                    <Card className='p-4 border-[1.5px] border-border-lt bg-bg rounded-sm'>
                        <p className='text-[11px] font-bold tracking-[0.08em] uppercase text-muted-foreground mb-3'>
                            위반 목록 ({violations.length}건)
                        </p>
                        {violations.length === 0 ? (
                            <p className='text-[12px] text-muted-foreground'>위반 단어 없음</p>
                        ) : (
                            <div className='flex flex-wrap gap-1.5'>
                                {violations.map((f) => (
                                    <Badge key={f.id} variant='destructive' className='text-[12px]'>
                                        {f.phwrdNm}
                                    </Badge>
                                ))}
                            </div>
                        )}
                    </Card>
                </div>
            </section>

            {/* 금칙어 목록 */}
            <section>
                <p className='text-[11px] font-bold tracking-[0.1em] uppercase text-muted-foreground mb-3'>금칙어 목록</p>
                <SearchForm
                    onSubmit={() => setRequest({
                        page: 1, size: request.size,
                        phwrdNm: emptyToNull(filters.phwrdNm),
                        useYn: emptyToNull(filters.useYn),
                    })}
                    onReset={() => { setFilters(initialFilters); setRequest({ page: 1, size: request.size }); }}
                >
                    <div className='grid w-full gap-3 md:grid-cols-2'>
                        <div className='space-y-2'>
                            <Label htmlFor='phwrdNm'>금칙어명</Label>
                            <Input id='phwrdNm' value={filters.phwrdNm}
                                onChange={(e) => setFilters((c) => ({ ...c, phwrdNm: e.target.value }))} />
                        </div>
                        <div className='space-y-2'>
                            <Label htmlFor='useYn'>사용여부</Label>
                            <Select value={filters.useYn || 'ALL'}
                                onValueChange={(v) => setFilters((c) => ({ ...c, useYn: v === 'ALL' ? '' : v }))}>
                                <SelectTrigger id='useYn' className='bg-background'><SelectValue placeholder='전체' /></SelectTrigger>
                                <SelectContent>
                                    <SelectItem value='ALL'>전체</SelectItem>
                                    <SelectItem value='Y'>사용</SelectItem>
                                    <SelectItem value='N'>미사용</SelectItem>
                                </SelectContent>
                            </Select>
                        </div>
                    </div>
                </SearchForm>

                <div className='mt-4'>
                    <CardList
                        pageData={pageQuery.data ?? null}
                        pageSizeOptions={[10, 20, 50, 100]}
                        onPageChange={({ page, size }) => setRequest((c) => ({ ...c, page, size }))}
                        renderItem={(forbidden) => <ForbiddenCard key={forbidden.id} forbidden={forbidden} />}
                    />
                </div>
            </section>
        </div>
    );
};
```

**중요:** axiosInstance 경로는 `src/shared/api/` Glob으로 먼저 확인 후 올바른 경로 사용.

