import { Link, useParams } from 'react-router-dom';
import { useQuery } from '@tanstack/react-query';
import { Badge } from '@/shared/components/ui/badge';
import { axiosInstance } from '@/core/api/axiosInstance';

const fetchDomain = (id) =>
    axiosInstance.get(`/api/v1/domains/${id}`).then((r) => r.data?.data ?? r.data);

export const DomainDetailPage = () => {
    const { id } = useParams();
    const { data: domain, isLoading, isError } = useQuery({
        queryKey: ['domain-detail', id],
        queryFn: () => fetchDomain(id),
        enabled: !!id,
    });

    if (isLoading) return <div className='p-6 text-sm text-muted-foreground'>불러오는 중...</div>;
    if (isError || !domain) return <div className='p-6 text-sm text-muted-foreground'>도메인을 찾을 수 없습니다.</div>;

    return (
        <div className='max-w-3xl space-y-8'>
            <div>
                <Link to='/app/domains' className='text-[12px] text-muted-foreground no-underline hover:text-fg'>
                    ← 목록으로
                </Link>
                <h1 className='font-display italic font-bold text-[32px] mt-3 mb-1' style={{ letterSpacing: '-0.02em' }}>
                    {domain.stdDmnNm}
                </h1>
                {domain.dataLen && (
                    <p className='text-[13px] font-mono text-muted-foreground'>
                        {domain.dataTypeNm}({domain.dataLen}{domain.unitNm ? ` ${domain.unitNm}` : ''})
                    </p>
                )}
                <div className='flex gap-2 mt-2'>
                    <Badge variant={domain.useYn === 'Y' ? 'success' : 'muted'}>
                        {domain.useYn === 'Y' ? '사용' : '미사용'}
                    </Badge>
                </div>
            </div>

            <section>
                <h2 className='text-[14px] font-bold mb-3 pb-2 border-b border-border-lt'>속성</h2>
                <table className='w-full text-[13px] border-collapse'>
                    <tbody>
                        {[
                            ['그룹명', domain.stdDmnGroupNm],
                            ['분류명', domain.stdDmnClsfNm],
                            ['데이터 타입', domain.dataTypeNm],
                            ['데이터 길이', domain.dataLen],
                            ['단위', domain.unitNm],
                            ['제정 차수', domain.enctCycl ? `${domain.enctCycl}차` : null],
                        ].map(([k, v]) => (
                            <tr key={k} className='border-b border-border-lt'>
                                <td className='py-2 pr-4 text-muted-foreground w-32 font-medium'>{k}</td>
                                <td className='py-2 font-mono'>{v ?? '—'}</td>
                            </tr>
                        ))}
                    </tbody>
                </table>
            </section>
        </div>
    );
};

import { useState, useMemo } from 'react';
